private struct AirbnbTabHost<Content: View>: View {
    let title: String
    let icon: String
    @ViewBuilder var content: () -> Content
    var body: some View { content() }
}

private enum AirbnbScreenFactory {
    @ViewBuilder
    static func screen(for tab: String) -> some View {
        switch tab.lowercased() {
        case let t where t.contains("explor") || t.contains("accueil") || t.contains("home") || t.contains("flight") || t.contains("airport"):
            AirbnbExploreScreen()
        case let t where t.contains("search") || t.contains("recherch"):
            AirbnbSearchScreen()
        case let t where t.contains("trip") || t.contains("voyage") || t.contains("book") || t.contains("wish") || t.contains("saved"):
            AirbnbTripsScreen()
        default:
            AirbnbGenericListScreen(title: tab)
        }
    }
}
